fun repeat(times: Int, action: () -> Unit) {
    for (i in 1..times) action()
}
repeat(3) {
    print("Hi ")
}

val add: (Int, Int) -> Int = { a, b -> a + b }
val multiply: (Int, Int) -> Int = { a, b -> a * b }
println(add(3, 4))
println(multiply(3, 4))

fun buildGreeter(prefix: String): () -> String {
    return { "$prefix, World!" }
}
val hi = buildGreeter("Hi")
val hello = buildGreeter("Hello")
println(hi())
println(hello())
